const raw = $input.first().json;
const d = raw.body || raw.query || raw;
d.runtime_mode = d.runtime_mode || "MOCK";
d.correlation_id = d.correlation_id || ("KNG-" + Date.now());
d.request_id = d.request_id || ("REQ-" + Math.random().toString(36).substr(2,8).toUpperCase());
d.user = d.user || {id:"system",name:"Auto",role:"user",department:"general"};
d.payload = d.payload || {};
d.metadata = d.metadata || {};
if (!d.payload.query && d.message) {
  d.payload.query = d.message;
}
const msg = (d.message || "").toLowerCase();
const q = (d.payload.query || "").toLowerCase();
if (!d.action) {
  if (d.payload.file_id || d.payload.file_name || d.payload.content) d.action = "sync_document";
  else if (d.payload.document_id && (/vigente|validar|vencido|check/.test(msg) || /vigente|validar|vencido|check/.test(q))) d.action = "verify_document";
  else if (d.payload.entity_type) d.action = "entity_memory";
  else if (/auditoria|\blog\b|rastrear|historico/.test(msg) || /auditoria|\blog\b|rastrear|historico/.test(q)) d.action = "audit_search";
  else if (/capa|plano de acao|corretiva|preventiva/.test(msg) || /capa|plano de acao|corretiva|preventiva/.test(q)) d.action = "capa_draft";
  else if (/nao conformidade|qualidade|falha/.test(msg) || /nao conformidade|qualidade|falha/.test(q)) d.action = "quality_check";
  else d.action = "query";
}
return [{json: d}];

