  risk = "critical";
} else if (cls.financial_related || cls.quality_related || ["verify_document", "capa_draft"].includes(d.action) || /fornecedor|aco|compra|proposta|cliente|\bop\b|kanban/i.test(q)) {
  risk = "high";
} else if (["entity_memory", "audit_search", "sync_document"].includes(d.action) || /historico|rastrear|manual/i.test(q)) {
  risk = "medium";
}
d._risk_level = risk;
d._requires_approval = (risk === "critical" && ["verify_document", "capa_draft"].includes(d.action)) || (risk === "critical" && d.action === "query");
return [{json: d}];

